/**
 * APP CONFIGURATION & PRIORITY MAPPING
 */
const integrityPriority = {
  "High Exposure Risk": 3,
  "High Risk": 2,
  "No Signal": 1
};
appsmith.onReady(() => {
  handleDataUpdate();
});
appsmith.onModelChange(() => {
  handleDataUpdate();
});
function handleDataUpdate() {
  const rawData = appsmith.model && appsmith.model.scriptData ? appsmith.model.scriptData : {};
  const persona = appsmith.model && appsmith.model.persona ? appsmith.model.persona : "Adult";
  const rootKey = Object.keys(rawData)[0];
  const scriptsMap = rootKey ? rawData[rootKey] : {};

  // 1. Transform JSON map into Model Risk Array
  let modelRisks = Object.entries(scriptsMap).map(([url, info]) => {
    const fileName = url.split('/').pop();
    const piiCount = (info.PIIs || []).length;
    const sensitiveCount = (info["sensitive PIIs"] || []).length;
    let safety = "No Signal";
    let findings = "No Signals Detected";
    if (sensitiveCount > 0) {
      safety = "High Exposure Risk";
      findings = `Found: ${(info["sensitive PIIs"] || []).join(', ')}`;
    } else if (piiCount > 0) {
      safety = "High Risk";
      findings = `Found: ${(info.PIIs || []).join(', ')}`;
    }
    return {
      name: fileName,
      leaks: piiCount + sensitiveCount,
      findings,
      safety
    };
  });

  // 2. SORTING LOGIC
  modelRisks.sort((a, b) => {
    const priorityDiff = integrityPriority[b.safety] - integrityPriority[a.safety];
    if (priorityDiff !== 0) return priorityDiff;
    return b.leaks - a.leaks;
  });
  renderDashboard(modelRisks, persona);
}
function renderDashboard(data, persona) {
  const listContainer = document.getElementById("risk-list");
  const violationList = document.getElementById("violation-list");
  const personaBadge = document.getElementById("persona-badge");
  if (personaBadge) personaBadge.innerText = `Persona: ${persona}`;
  if (listContainer) listContainer.innerHTML = "";
  if (violationList) violationList.innerHTML = "";
  let totalLeaks = 0;
  let totalAdversarial = 0;
  let violationHtml = "";
  if (data.length === 0) {
    if (listContainer) listContainer.innerHTML = `<div class="empty-state">No assets analyzed.</div>`;
    if (violationList) violationList.innerHTML = `<div class="empty-state">No violations detected.</div>`;
  }
  data.forEach(item => {
    totalLeaks += item.leaks;
    if (item.safety !== "No Signal") totalAdversarial++;
    const isCritical = item.safety === "High Exposure Risk";
    const integrityClass = isCritical ? "critical" : item.safety === "High Risk" ? "warning" : "safe";
    const rowClass = isCritical ? "list-item critical-row" : "list-item";
    const icon = isCritical ? "🚨" : item.safety === "High Risk" ? "⚠️" : "📦";

    // Render Asset List Item
    if (listContainer) {
      const div = document.createElement('div');
      div.className = rowClass;
      div.innerHTML = `
                <div class="item-main">
                    <div class="item-icon">${icon}</div>
                    <div class="item-details">
                        <div class="item-title">${item.name}</div>
                        <div class="item-meta"><strong>Adversarial Findings:</strong> ${item.findings}</div>
                    </div>
                </div>
                <div class="item-actions">
                    <span class="status-badge ${integrityClass}">${item.safety}</span>
                    <span class="evidence-tag">${item.leaks} instances</span>
                </div>
            `;
      listContainer.appendChild(div);
    }

    // Render Violation Tracker Item
    if (item.leaks > 0) {
      violationHtml += `
                <div class="alert-card">
                    <div class="alert-header">
                        <span>●</span> OBSERVED SIGNAL
                    </div>
                    <div class="alert-body">
                        <code>${item.name}</code> contains <b>${item.safety}</b> data markers.
                    </div>
                </div>
            `;
    }
  });
  if (violationList) {
    violationList.innerHTML = violationHtml || `<div class="empty-state">System secure. No high-severity signals observed.</div>`;
  }

  // Update Top Level Metrics
  document.getElementById("total-chunks").innerText = data.length;
  document.getElementById("pii-count").innerText = totalLeaks;
  document.getElementById("sensitive-count").innerText = totalAdversarial;
  let baseScore = totalLeaks * 1.2 + totalAdversarial * 15;
  if (persona.toLowerCase().includes("minor")) baseScore *= 2.5;
  const riskScoreEl = document.getElementById("risk-score");
  if (riskScoreEl) {
    riskScoreEl.innerText = baseScore.toFixed(1);
    riskScoreEl.parentElement.style.background = baseScore > 20 ? "linear-gradient(135deg, #e74c3c 0%, #c0392b 100%)" : "linear-gradient(135deg, #f39c12 0%, #d35400 100%)";
  }
  const complianceStatus = document.getElementById("compliance-status");
  if (complianceStatus) {
    complianceStatus.innerText = totalAdversarial > 0 ? "Failing" : "Observed Secure";
    complianceStatus.style.color = totalAdversarial > 0 ? "#e74c3c" : "#2ecc71";
  }
}

